INSERT INTO `Inciso` (`IncisoID`, `LeiID`, `ArtigoID`, `Nome`, `Texto`) VALUES
(1, 2, 1, 'I', 'documento de formalização de demanda e, se for o caso, estudo técnico preliminar, análise de riscos, termo de referência, projeto básico ou projeto executivo;'),
(2, 2, 1, 'II', 'estimativa de despesa, que deverá ser calculada na forma estabelecida no art. 23 desta Lei;'),
(3, 2, 1, 'III', 'parecer jurídico e pareceres técnicos, se for o caso, que demonstrem o atendimento dos requisitos exigidos;'),
(4, 2, 1, 'IV', 'demonstração da compatibilidade da previsão de recursos orçamentários com o compromisso a ser assumido;'),
(5, 2, 2, 'I', 'aquisição de materiais, de equipamentos ou de gêneros ou contratação de serviços que só possam ser fornecidos por produtor, empresa ou representante comercial exclusivos;'),
(6, 2, 2, 'II', 'contratação de profissional do setor artístico, diretamente ou por meio de empresário exclusivo, desde que consagrado pela crítica especializada ou pela opinião pública;'),
(7, 2, 2, 'III', 'contratação dos seguintes serviços técnicos especializados de natureza predominantemente intelectual com profissionais ou empresas de notória especialização, vedada a inexigibilidade para serviços de publicidade e divulgação'),
(8, 2, 3, 'I', 'para contratação que envolva valores inferiores a R$ 100.000,00 (cem mil reais), no caso de obras e serviços de engenharia ou de serviços de manutenção de veículos automotores;'),
(9, 2, 3, 'II', 'para contratação que envolva valores inferiores a R$ 50.000,00 (cinquenta mil reais), no caso de outros serviços e compras;'),
(10, 2, 3, 'III', 'para contratação que mantenha todas as condições definidas em edital de licitação realizada há menos de 1 (um) ano, quando se verificar que naquela licitação'),
(11, 2, 4, 'I -', 'os documentos serão produzidos por escrito, com data e local de sua realização e assinatura dos responsáveis;');
INSERT INTO `ItemAcompanhamento` (`ItemAcompanhamentoID`, `ModalidadeCompraID`, `LeiID`, `Item`, `Observacao`, `OrdemApresentacao`) VALUES
(1, 2, 2, 'a) Extensão do direito à participação àquele\ninteressado ainda não cadastrado, que tenha\natendido a todas as exigências para o\ncadastramento até o terceiro dia útil anterior\nà data do recebimento das propostas ', 'art. 22, §2º, da Lei Federal n. 8.666/93\n', 1),
(2, 2, 2, 'b) Exigência, dos interessados não\ncadastrados, somente daqueles documentos\nque comprovem habilitação compatível com\no objeto da licitação, nos termos do edital e\ndos arts. 27 a 31 da Lei Federal n. 8.666/93', 'art. 22, §9º, da Lei Federal n. 8.666/93\nhghfghfg', 2),
(3, 2, 2, 'c) Respeito aos prazos mínimos previstos no\nart. 21, §2º, da Lei n. 8.666/93 \n', 'Na Tomada de Preços, quando a licitação\nfor do tipo “melhor técnica” ou “técnica e\npreço”, deve ser respeitado o prazo de 30\n(trinta) dias. Nos demais casos, o prazo é\nde 15 (quinze) dias\n', 3),
(4, 6, 2, 'fkldsfklsd fskl dfjskldfsdfskljskldf', '', 0);
INSERT INTO `Lei` (`LeiID`, `Nome`) VALUES
(1, 'Lei nº 8.666/1993'),
(2, 'Lei nº 14.133/2021');
