INSERT INTO `Modelos` (`idModelo`, `TextoModelo`) VALUES
('DFD', 'Memorando n° xxx/ANO\nÀ ... (unidade de compras do órgão),\nSolicito que seja providenciada a solução para ... (expor o problema a ser\nsolucionado e ajuste a ortografia dos textos).\nEstimo que o quantitativo necessário é de ... (indicar a quantidade x periodicidade).\nInformo que a aquisição deve ser feita até ... (indicar prazo para o término\ndo processo de compra), considerando que ... (justificar o prazo indicado).\n(Inclua a observação caso haja e ajuste a redação e ortografia)\nPor fim, ressalto que a compra pretendida: (trazer as duas opções abaixo, apenas marcando a correta)\n( ) está prevista no Plano de Contratações Anual deste exercício.\n( ) não está prevista no Plano de Contratações Anual deste exercício.\n\nBelém / PA, (data criação por extenso).\n\nAtenciosamente,\n\nNOME do RESPONSÁVEL (Caixa alta)\n(Cargo)\nMatricula: (matrícula)');
INSERT INTO `Orgao` (`OrgaoID`, `Nome`) VALUES
(1, 'ESTADO DO PARÁ');
INSERT INTO `pca_classificacao` (`id`, `nome`, `descricao`, `instrucao_ia`, `ativo`) VALUES
(4, 'Material de Consumo', 'Materiais utilizados rotineiramente que se desgastam com o uso e têm vida útil inferior a dois anos.', 'Utilizado rotineiramente e se desgasta com o uso ou perde a identidade física em menos de dois anos. Exemplos: papel, toner, copos descartáveis, EPIs, produtos de limpeza, insumos de escritório.', 1),
(5, 'Material Permanente', 'Bens duráveis que mantêm sua identidade física por mais de dois anos.', 'Mantém sua identidade física por mais de dois anos e é reutilizável. Exemplos: móveis, eletrônicos, ar-condicionado, equipamentos de escritório ou laboratório.', 1),
(6, 'Serviço Comum', 'Serviços rotineiros, operacionais e padronizados, sem caráter técnico especializado.', 'Refere-se a contratações de serviços padronizados e rotineiros (ex.: limpeza, conservação, manutenção, vigilância, transporte, jardinagem, portaria).', 1),
(7, 'Serviço Especializado', 'Serviços técnicos ou intelectuais que exigem conhecimento especializado.', 'Envolve execução de atividade técnica especializada, intelectual ou artística (ex.: consultoria, auditoria, capacitação técnica, engenharia, advocacia, desenvolvimento de software).', 1),
(8, 'Tecnologia da Informação (TI)', 'Aquisição de bens ou serviços relacionados à tecnologia da informação e comunicação.', 'Itens, softwares ou serviços ligados à área de tecnologia da informação e comunicação (ex.: computadores, licenças, hospedagem, manutenção de sistemas, equipamentos de rede).', 1),
(9, 'Frota e Transporte', 'Itens e serviços ligados a veículos, transporte e mobilidade.', 'Relativo a veículos automotores, transporte e mobilidade (ex.: compra de veículos, manutenção automotiva, locação de frota, combustível, pneus, peças).', 1),
(10, 'Obras e Engenharia', 'Execução de obras civis, reformas, construções e serviços de engenharia.', 'Refere-se a obras de construção civil, reformas, ampliações e serviços de engenharia (ex.: pavimentação, obras prediais, manutenção elétrica ou hidráulica).', 1),
(11, 'Geral / Outros', 'Categoria genérica para itens ou serviços não enquadrados nas demais classificações.', 'Utilizado para itens ou serviços genéricos, multidisciplinares ou não classificados (ex.: eventos, publicidade, brindes, materiais diversos).', 1),
(12, 'Não se aplica', 'Usado para itens que não representam bens nem serviços.', 'Casos em que não se trata de aquisição, mas sim de ações administrativas, termos de cooperação, parcerias ou outros itens sem natureza de bem ou serviço.', 1);
