(120, 0, 0, 'rodrigo.campos@sefa.pa.gov.br', 3, 1, 1, 1, 0, 'Software Adobe Acrobat Pro Teams - por 12 meses/com renovações anuais', 3.00, 1320.00, 3960.00, 'Finalidade: edição avançada de documentos PDF, comparação de versões normativas, assinaturas digitais e marcações técnicas.\nAplicação: processamento de legislação e controle de versões.\nModernização dos processos de trabalho por meio da implementação de soluções tecnológicas avançadas e capacitação especializada, assegurando maior eficiência, qualidade e conformidade normativa.\n', 3, 4, 7, NULL, '2026-01-01', '2025-08-28 15:48:54', '2025-10-05 12:21:43', 'software adobe acrobat pro', '', 8, NULL, 0),
