(252, 0, 0, 'lmota@sefa.pa.gov.br', 3, 3, 1, 5, 0, 'TELHADO', 15.00, 46.67, 700.05, 'Anualmente no periodo do inverno amazônico com as chuvas fortes começam a surgir goteiras no telhado da CERAT SEDE', 3, 3, 6, NULL, NULL, '2025-08-30 17:53:30', '2025-10-05 12:21:44', 'telhado', '', 11, NULL, 0),
