(1246, 0, 0, 'rita.paganelli@sefa.pa.gov.br', 1, 1, 1, 1, 0, 'Jabra Evolve 20 MS Stereo Headset - Fones de ouvido com cancelamento de ruído passívo, cabo USB com controle de chamada - preto', 10.00, 369.00, 3690.00, 'Ingresso de novos servidores em decorrência da realização de concurso na SEFA-PA. Estima-se que pelo menos 10 servidores será lotado na DTR, necessitando de equipamento para desempenho de suas atribuições.', 1, 4, 5, NULL, '2026-01-01', '2025-09-05 17:20:24', '2025-10-05 12:21:44', 'jabra evolve 20 ms', '', 11, NULL, 0),
(1247, 0, 0, 'luisa.rodrigues@sefa.pa.gov.br', 5, 5, 1, 1, 0, 'LIQUIDIFICADOR INDUSTRIAL', 6.00, 200.00, 1200.00, 'CONSIDERADO QUE NAO TEMOS PARA USO NA UNIDADES DA CECOMT ARAGUIA , UECOMTS E RESIDENCIA ', 3, 4, 7, NULL, NULL, '2025-09-05 17:30:26', '2025-10-05 12:21:44', 'liquidificador industrial', '', 11, NULL, 0),
