(1265, 0, 0, 'machael.costa@sefa.pa.gov.br', 3, 3, 1, 5, 0, 'Contratação de Empresa Especializada para Fornecimento de buffet', 300.00, 18.00, 5400.00, 'A presente contratação visa atender às demandas das ações de saúde e valorização dos servidores promovidas pelo setor Psicossocial da Secretaria da Fazenda (SEFA). Tais ações são parte integrante da política institucional de promoção do bem-estar, engajamento e reconhecimento dos profissionais que atuam na SEFA.\n\nO fornecimento de kit lanche — composto por itens variados e nutritivos como salgados, bolo regional com cobertura de cupuaçu e suco natural — será destinado aos participantes dos eventos e campanhas realizadas ao longo do ano, como rodas de conversa, oficinas temáticas, palestras e atendimentos em grupo. Esses momentos são fundamentais para fortalecer vínculos, promover saúde mental e estimular a valorização do servidor público.\n\nA escolha do fornecedor especializado em buffet justifica-se pela necessidade de garantir:\n\nQualidade e segurança alimentar;\nPadronização no atendimento aos participantes;\nAgilidade na entrega e logística compatível com os eventos;\nCusto-benefício adequado ao orçamento previsto.', 1, 3, 4, NULL, NULL, '2025-09-05 19:00:22', '2025-10-05 12:21:44', 'contratação de empresa especializada', '', 11, NULL, 0),
(1251, 0, 0, 'glbarbosa@sefa.pa.gov.br', 3, 3, 1, 5, 0, 'HIGIENIZAÇÃO DAS CADEIRAS DO ATENDIMENTO', 38.00, 55.00, 2090.00, 'HIENIZAÇÃO DO TECIDO DAS CADEIRAS UTILIZADAS NO ATENDIMENTO', 1, 3, 4, NULL, '2026-03-02', '2025-09-05 18:06:51', '2025-10-05 12:21:44', 'higienização das cadeiras do', '', 5, NULL, 0),
