(1679, 0, 0, 'rafaelle.braga@sefa.pa.gov.br', 5, 5, 1, 1, 0, 'Smart TV 43” Full HD QLED com sistema operacional, processador Quad Core, Dolby Audio, HDMI e USB.', 4.00, 1500.00, 6000.00, 'Duas serão utilizadas como painel fixo de exibição contínua de dashboards de monitoramento de sistemas, infraestrutura, segurança da informação e indicadores de desempenho e outras duas nas salas de reunião pequenas do andar térreo, que terá na DTI após reforma. Essas Tvs serão utilizadas como monitor externo para notebooks durante reuniões, apresentações de projetos, treinamentos etc.', 1, 4, 5, NULL, '2026-02-02', '2025-09-12 11:39:45', '2025-10-05 12:21:44', 'smart tv 43 full', '', 8, NULL, 0),
(1680, 0, 0, 'rafaelle.braga@sefa.pa.gov.br', 5, 5, 1, 1, 0, 'Smart TV 65” TCL QLED 4K Ultra HD com Sistema Operacional, HDMI 2.1, Chromecast built-in, Dolby Vision, conexão HDMI/USB/WIFI.', 1.00, 3000.00, 3000.00, '	\nSerá utilizada como tela na segunda sala de reunião que terá na DTI, após reforma.\nA Tela substitui a necessidade de projetores, oferecendo maior praticidade, qualidade de imagem e conectividade durante reuniões, apresentações de projetos, treinamentos etc.', 0, 0, 0, NULL, '2026-12-01', '2025-09-12 11:45:31', '2025-10-05 12:21:44', 'smart tv 65 tcl', '', 8, NULL, 0),
