INSERT INTO `pca_itens` (`id`, `plano_id`, `setor_id`, `usuario_demandante`, `categoria_id`, `recategorizacao_id`, `entra_pca`, `unidade_medida_id`, `status_id`, `objeto`, `quantidade`, `valor_unitario_estimado`, `valor_total_estimado`, `justificativa_necessidade`, `complexidade`, `relevancia`, `prioridade`, `data_prevista_tr`, `data_prevista_contrato`, `created_at`, `updated_at`, `frase_simplificada`, `grupo_sugerido`, `classificacao_id`, `area_de_negocios`, `natureza_despesa`) VALUES
(1910, 0, 0, 'anasilva@sefa.pa.gov.br', 6, 5, 1, 1, 0, 'Cadeira Escolar - VN 2 Rodízios; Estrutura metálica; Assento polipropileno; Empilhável; Rodízios', 32.00, 447.35, 14315.20, 'A aquisição de mobiliário específico para a sala de aula multiuso da Escola Fazendária (EFAZ) é essencial para viabilizar a aplicação de metodologias ágeis no processo de ensino-aprendizagem. O novo espaço será utilizado para capacitações, oficinas e treinamentos que demandam flexibilidade, mobilidade e interação entre os participantes. O mobiliário adequado permitirá a reorganização rápida do ambiente, favorecendo dinâmicas colaborativas, trabalho em grupo e inovação pedagógica, alinhando-se às diretrizes modernas de formação continuada no serviço público.', 2, 3, 5, NULL, '2026-04-01', '2025-09-15 19:14:43', '2025-10-05 12:21:44', 'cadeira escolar vn 2', '', 4, NULL, 0),
(1911, 0, 0, 'anasilva@sefa.pa.gov.br', 6, 5, 1, 1, 0, 'Cadeira VN Giratória - Estrutura (cinza ou preta); Assento polipropileno; Ajuste de altura; Rodízios', 4.00, 792.35, 3169.40, 'A aquisição de mobiliário específico para a sala de aula multiuso da Escola Fazendária (EFAZ) é essencial para viabilizar a aplicação de metodologias ágeis no processo de ensino-aprendizagem. O novo espaço será utilizado para capacitações, oficinas e treinamentos que demandam flexibilidade, mobilidade e interação entre os participantes. O mobiliário adequado permitirá a reorganização rápida do ambiente, favorecendo dinâmicas colaborativas, trabalho em grupo e inovação pedagógica, alinhando-se às diretrizes modernas de formação continuada no serviço público.', 2, 3, 5, NULL, '2026-03-10', '2025-09-15 19:16:50', '2025-10-05 12:21:44', 'cadeira vn giratória estrutura', '', 5, NULL, 0),
