DROP TABLE IF EXISTS `vw_convenios_encerrados`;

CREATE ALGORITHM=UNDEFINED DEFINER=`eventossefa`@`localhost` SQL SECURITY DEFINER VIEW `vw_convenios_encerrados`  AS SELECT `c`.`Id` AS `Id`, `c`.`NumeroConvenio` AS `NumeroConvenio`, `c`.`Ano` AS `Ano`, `c`.`Objeto` AS `Objeto`, `c`.`VigenciaInicio` AS `VigenciaInicio`, `c`.`VigenciaFim` AS `VigenciaFim`, `c`.`ValorGlobal` AS `ValorGlobal`, `c`.`ValorRepasse` AS `ValorRepasse`, `c`.`ValorContrapartida` AS `ValorContrapartida`, `c`.`Situacao` AS `Situacao`, `c`.`PrestadorId` AS `PrestadorId`, `c`.`DiretoriaId` AS `DiretoriaId`, `c`.`UnidadeGestoraId` AS `UnidadeGestoraId` FROM `Convenio` AS `c` WHERE ((`c`.`Situacao` in ('Encerrado','Cancelado')) OR ((`c`.`VigenciaFim` is not null) AND (`c`.`VigenciaFim` < curdate()))) ;

