CREATE ALGORITHM=UNDEFINED DEFINER=`eventossefa`@`localhost` SQL SECURITY DEFINER VIEW `vw_convenio_financeiro`  AS SELECT `c`.`Id` AS `ConvenioId`, `c`.`NumeroConvenio` AS `NumeroConvenio`, `c`.`Ano` AS `Ano`, `c`.`Objeto` AS `Objeto`, `c`.`ValorGlobal` AS `ValorGlobal`, `c`.`ValorRepasse` AS `ValorRepasse`, `c`.`ValorContrapartida` AS `ValorContrapartida`, sum((case when (`d`.`Tipo` = 'Repasse') then `d`.`Valor` else 0 end)) AS `TotalRepasseEfetivo`, sum((case when (`d`.`Tipo` = 'Contrapartida') then `d`.`Valor` else 0 end)) AS `TotalContrapartidaEfetiva`, sum((case when (`d`.`Tipo` = 'Devolução') then `d`.`Valor` else 0 end)) AS `TotalDevolvido` FROM (`Convenio` `c` left join `Convenio_Desembolso` `d` on((`d`.`ConvenioId` = `c`.`Id`))) GROUP BY `c`.`Id`, `c`.`NumeroConvenio`, `c`.`Ano`, `c`.`Objeto`, `c`.`ValorGlobal`, `c`.`ValorRepasse`, `c`.`ValorContrapartida` ;

